parameters.body:
={
  "name": "Sofia - {{ $('Webhook Trigger').item.json.body.business_name }}",
  "model": {
    "provider": "openai",
    "model": "gpt-4o",
    "systemPrompt": "{{ $('Generate VAPI Prompt').item.json.choices[0].message.content }}"
  },
  "voice": {
    "provider": "11labs",
    "voiceId": "21m00Tcm4TlvDq8ikWAM"
  },
  "firstMessage": "Ciao! Sono Sofia, l'assistente virtuale di {{ $('Webhook Trigger').item.json.body.business_name }}. Come posso aiutarti oggi?",
  "language": "it-IT"
}

={
  "from": "Flowstart AI <onboarding@flowstart.it>",
  "to": ["{{ $('Webhook Trigger').item.json.body.customer_email }}"],
  "subject": "Benvenuto in Flowstart AI — Il tuo agente è in configurazione",
  "html": "<h1>Benvenuto in Flowstart AI</h1><p>Ciao,</p><p>il tuo assistente AI <strong>Sofia</strong> è in fase di configurazione per <strong>{{ $('Webhook Trigger').item.json.body.business_name }}</strong>.</p><p>Il nostro team ti contatterà entro 24 ore per completare la configurazione e attivare il tuo numero di telefono dedicato.</p><p>Nel frattempo puoi accedere al tuo pannello:</p><p><a href='{{ $env.NEXT_PUBLIC_SITE_URL }}/dashboard'>Accedi al pannello →</a></p><p>A presto,<br>Il team Flowstart AI</p>"
}

={
  "from": "Flowstart AI <team@flowstart.it>",
  "to": ["hello@flowstart.it"],
  "subject": "Nuovo cliente: {{ $('Webhook Trigger').item.json.body.business_name }}",
  "html": "<h2>Nuovo cliente onboarding</h2><ul><li><strong>Business:</strong> {{ $('Webhook Trigger').item.json.body.business_name }}</li><li><strong>Piano:</strong> {{ $('Webhook Trigger').item.json.body.plan }}</li><li><strong>Email:</strong> {{ $('Webhook Trigger').item.json.body.customer_email }}</li><li><strong>Tenant ID:</strong> {{ $('Webhook Trigger').item.json.body.tenant_id }}</li><li><strong>VAPI ID:</strong> {{ $('Create VAPI Assistant').item.json.id }}</li></ul><p><strong>Azione richiesta:</strong> Assegnare numero di telefono e attivare agente.</p>"
}
